INSERT OR REPLACE INTO content_lessons (content_version_id, lesson_id, lesson_type, sort_order, title, summary, payload_json)
VALUES ('pl-en-v1', 'lesson-01', 'pronunciation', 10, 'Wymowa angielska', 'Angielskie dźwięki, które polscy użytkownicy powinni najpierw usłyszeć i przećwiczyć: th, w/v, angielskie r, h, ng, krótkie samogłoski, schwa i końcowe zbitki spółgłosek.', '{"id":"lesson-01","title":"Wymowa angielska","summary":"Angielskie dźwięki, które polscy użytkownicy powinni najpierw usłyszeć i przećwiczyć: th, w/v, angielskie r, h, ng, krótkie samogłoski, schwa i końcowe zbitki spółgłosek.","schema":"langbangml.pl-en.compat.v1","sourceLocale":"pl-PL","targetLocale":"en-US","targetField":"pl","sourceField":"en","fieldLocales":{"pl":"en-US","en":"pl-PL","source":"pl-PL","target":"en-US"},"phonemes":[{"letter":"th","name":"bezdźwięczne th","ipa":"/θ/","englishApproximation":"Połóż czubek języka lekko między zębami; to nie jest polskie f, t ani s.","description":"Miękki przepływ powietrza bez głosu. Wypowiedz krótko i nie dodawaj samogłoski po dźwięku.","examples":[{"pl":"think","en":"myśleć"},{"pl":"thin","en":"cienki"},{"pl":"thanks","en":"dzięki"},{"pl":"three","en":"trzy"},{"pl":"bath","en":"kąpiel"},{"pl":"with","en":"z"}]},{"letter":"th","name":"dźwięczne th","ipa":"/ð/","englishApproximation":"Ten sam układ języka co przy /θ/, ale z głosem; to nie jest d ani z.","description":"Włącz wibrację w gardle, a język zostaw lekko między zębami.","examples":[{"pl":"this","en":"to"},{"pl":"that","en":"tamto"},{"pl":"they","en":"oni / one"},{"pl":"the","en":"the"},{"pl":"mother","en":"matka"},{"pl":"weather","en":"pogoda"}]},{"letter":"r","name":"angielskie r","ipa":"/ɹ/","englishApproximation":"Angielskie r nie jest rolowane. Język cofa się i nie uderza o podniebienie.","description":"Trzymaj język napięty i lekko cofnięty; bez polskiego drżenia r.","examples":[{"pl":"red","en":"czerwony"},{"pl":"read","en":"czytać"},{"pl":"right","en":"prawo / dobrze"},{"pl":"around","en":"dookoła"},{"pl":"sorry","en":"przepraszam"},{"pl":"car","en":"samochód"}]},{"letter":"w","name":"angielskie w","ipa":"/w/","englishApproximation":"Zaokrąglij usta przed samogłoską. Polskie w brzmi bliżej angielskiego v, więc tu potrzebny jest wyraźny ruch ust.","description":"Zacznij od ust ułożonych jak do u, potem płynnie przejdź w samogłoskę.","examples":[{"pl":"water","en":"woda"},{"pl":"want","en":"chcieć"},{"pl":"window","en":"okno"},{"pl":"we","en":"my"},{"pl":"work","en":"praca"},{"pl":"woman","en":"kobieta"}]},{"letter":"v","name":"angielskie v","ipa":"/v/","englishApproximation":"Angielskie v jest jak polskie w: zęby dotykają dolnej wargi i głos jest włączony.","description":"Nie zaokrąglaj ust tak jak przy angielskim w.","examples":[{"pl":"very","en":"bardzo"},{"pl":"voice","en":"głos"},{"pl":"visit","en":"odwiedzać"},{"pl":"love","en":"miłość"},{"pl":"have","en":"mieć"},{"pl":"move","en":"ruszać się"}]},{"letter":"h","name":"angielskie h","ipa":"/h/","englishApproximation":"Angielskie h to lekki oddech. Nie powinno zamieniać się w polskie ch /x/.","description":"Wypuść powietrze swobodnie z gardła, bez szorstkiego tarcia.","examples":[{"pl":"hello","en":"cześć"},{"pl":"happy","en":"szczęśliwy"},{"pl":"house","en":"dom"},{"pl":"hungry","en":"głodny"},{"pl":"help","en":"pomoc"},{"pl":"hot","en":"gorący"}]},{"letter":"ng","name":"końcowe ng","ipa":"/ŋ/","englishApproximation":"Końcowy dźwięk w sing powstaje z tyłu jamy ustnej. Nie dodawaj po nim twardego g.","description":"Pozwól, żeby dźwięk zakończył się nosowo, jak na końcu angielskiego sing.","examples":[{"pl":"sing","en":"śpiewać"},{"pl":"long","en":"długi"},{"pl":"thing","en":"rzecz"},{"pl":"morning","en":"rano"},{"pl":"thinking","en":"myślenie"},{"pl":"walking","en":"chodzenie"}]},{"letter":"i","name":"krótkie i","ipa":"/ɪ/","englishApproximation":"Krótkie i jest rozluźnione, między polskim y i i.","description":"Nie przeciągaj go jak polskiego i /i/.","examples":[{"pl":"sit","en":"siedzieć"},{"pl":"big","en":"duży"},{"pl":"this","en":"to"},{"pl":"milk","en":"mleko"},{"pl":"city","en":"miasto"},{"pl":"listen","en":"słuchać"}]},{"letter":"ee","name":"długie ee","ipa":"/iː/","englishApproximation":"Długie ee jest napięte i trwa dłużej niż krótkie i.","description":"Uśmiechnij się lekko i utrzymaj samogłoskę równo.","examples":[{"pl":"see","en":"widzieć"},{"pl":"read","en":"czytać"},{"pl":"eat","en":"jeść"},{"pl":"street","en":"ulica"},{"pl":"green","en":"zielony"},{"pl":"sleep","en":"spać"}]},{"letter":"a","name":"samogłoska trap","ipa":"/æ/","englishApproximation":"Ta samogłoska jest szersza niż polskie e, ale mniej otwarta niż polskie a.","description":"Otwórz usta, trzymaj język z przodu i nie zamieniaj jej w e.","examples":[{"pl":"cat","en":"kot"},{"pl":"man","en":"mężczyzna"},{"pl":"happy","en":"szczęśliwy"},{"pl":"family","en":"rodzina"},{"pl":"bad","en":"zły"},{"pl":"that","en":"tamto"}]},{"letter":"u","name":"samogłoska strut","ipa":"/ʌ/","englishApproximation":"Samogłoska w cup jest centralna i krótka. To nie jest polskie a ani o.","description":"Wypowiedz ją luźno i krótko.","examples":[{"pl":"cup","en":"kubek"},{"pl":"love","en":"miłość"},{"pl":"must","en":"musieć"},{"pl":"mother","en":"matka"},{"pl":"fun","en":"zabawa"},{"pl":"under","en":"pod"}]},{"letter":"schwa","name":"schwa","ipa":"/ə/","englishApproximation":"Najczęstsza słaba samogłoska w angielskim. Jest krótka, neutralna i nieakcentowana.","description":"Nie wymawiaj każdej zapisanej samogłoski pełnym dźwiękiem.","examples":[{"pl":"about","en":"o / około"},{"pl":"today","en":"dzisiaj"},{"pl":"open","en":"otwarty"},{"pl":"teacher","en":"nauczyciel"},{"pl":"person","en":"osoba"},{"pl":"again","en":"znowu"}]},{"letter":"er","name":"akcentowane er","ipa":"/ɜːr/","englishApproximation":"To samogłoska z odcieniem r w word i work.","description":"Przytrzymaj centralną samogłoskę i zachowaj układ angielskiego r.","examples":[{"pl":"word","en":"słowo"},{"pl":"work","en":"pracować"},{"pl":"girl","en":"dziewczyna"},{"pl":"first","en":"pierwszy"},{"pl":"learn","en":"uczyć się"},{"pl":"turn","en":"skręcić"}]},{"letter":"finals","name":"końcowe spółgłoski","ipa":"/-t -d -k -p -s/","englishApproximation":"Angielski często kończy słowa ostro. Nie dodawaj dodatkowej samogłoski po końcowej spółgłosce.","description":"Zakończ spółgłoskę czysto, szczególnie w zbitkach.","examples":[{"pl":"asked","en":"zapytał"},{"pl":"helped","en":"pomógł"},{"pl":"walked","en":"szedł"},{"pl":"books","en":"książki"},{"pl":"next","en":"następny"},{"pl":"world","en":"świat"}]}]}');
INSERT OR REPLACE INTO content_lessons (content_version_id, lesson_id, lesson_type, sort_order, title, summary, payload_json)
VALUES ('pl-en-v1', 'lesson-02', 'verbs', 20, 'Lekcja 2 — czasowniki angielskie', 'Ten sam podstawowy zestaw czasowników, odwrócony dla polskich użytkowników uczących się angielskiego. Angielski cel jest pierwszy, a polski zostaje jako podpowiedź.', '{"id":"lesson-02","title":"Lekcja 2 — czasowniki angielskie","summary":"Ten sam podstawowy zestaw czasowników, odwrócony dla polskich użytkowników uczących się angielskiego. Angielski cel jest pierwszy, a polski zostaje jako podpowiedź.","schema":"langbangml.pl-en.compat.v1","sourceLocale":"pl-PL","targetLocale":"en-US","targetField":"pl","sourceField":"en","fieldLocales":{"pl":"en-US","en":"pl-PL","source":"pl-PL","target":"en-US"},"verbs":[{"lemma":"be","en":"być","forms":{"1sg":"am","2sg":"are","3sg":"is","1pl":"are","2pl":"are","3pl":"are"},"past_forms":{"1sg":"was","2sg":"were","3sg":"was","1pl":"were","2pl":"were","3pl":"were"}},{"lemma":"have","en":"mieć","forms":{"1sg":"have","2sg":"have","3sg":"has","1pl":"have","2pl":"have","3pl":"have"},"past_forms":{"1sg":"had","2sg":"had","3sg":"had","1pl":"had","2pl":"had","3pl":"had"}},{"lemma":"go","en":"iść","forms":{"1sg":"go","2sg":"go","3sg":"goes","1pl":"go","2pl":"go","3pl":"go"},"past_forms":{"1sg":"went","2sg":"went","3sg":"went","1pl":"went","2pl":"went","3pl":"went"}},{"lemma":"eat","en":"jeść","forms":{"1sg":"eat","2sg":"eat","3sg":"eats","1pl":"eat","2pl":"eat","3pl":"eat"},"past_forms":{"1sg":"ate","2sg":"ate","3sg":"ate","1pl":"ate","2pl":"ate","3pl":"ate"}},{"lemma":"drink","en":"pić","forms":{"1sg":"drink","2sg":"drink","3sg":"drinks","1pl":"drink","2pl":"drink","3pl":"drink"},"past_forms":{"1sg":"drank","2sg":"drank","3sg":"drank","1pl":"drank","2pl":"drank","3pl":"drank"}},{"lemma":"do","en":"robić","forms":{"1sg":"do","2sg":"do","3sg":"does","1pl":"do","2pl":"do","3pl":"do"},"past_forms":{"1sg":"did","2sg":"did","3sg":"did","1pl":"did","2pl":"did","3pl":"did"}},{"lemma":"speak","en":"mówić","forms":{"1sg":"speak","2sg":"speak","3sg":"speaks","1pl":"speak","2pl":"speak","3pl":"speak"},"past_forms":{"1sg":"spoke","2sg":"spoke","3sg":"spoke","1pl":"spoke","2pl":"spoke","3pl":"spoke"}},{"lemma":"see","en":"widzieć","forms":{"1sg":"see","2sg":"see","3sg":"sees","1pl":"see","2pl":"see","3pl":"see"},"past_forms":{"1sg":"saw","2sg":"saw","3sg":"saw","1pl":"saw","2pl":"saw","3pl":"saw"}},{"lemma":"like","en":"lubić","forms":{"1sg":"like","2sg":"like","3sg":"likes","1pl":"like","2pl":"like","3pl":"like"},"past_forms":{"1sg":"liked","2sg":"liked","3sg":"liked","1pl":"liked","2pl":"liked","3pl":"liked"}},{"lemma":"read","en":"czytać","forms":{"1sg":"read","2sg":"read","3sg":"reads","1pl":"read","2pl":"read","3pl":"read"},"past_forms":{"1sg":"read","2sg":"read","3sg":"read","1pl":"read","2pl":"read","3pl":"read"}},{"lemma":"pay","en":"płacić","forms":{"1sg":"pay","2sg":"pay","3sg":"pays","1pl":"pay","2pl":"pay","3pl":"pay"},"past_forms":{"1sg":"paid","2sg":"paid","3sg":"paid","1pl":"paid","2pl":"paid","3pl":"paid"}},{"lemma":"know (a fact)","en":"wiedzieć","forms":{"1sg":"know","2sg":"know","3sg":"knows","1pl":"know","2pl":"know","3pl":"know"},"past_forms":{"1sg":"knew","2sg":"knew","3sg":"knew","1pl":"knew","2pl":"knew","3pl":"knew"}},{"lemma":"know (a person/thing)","en":"znać","forms":{"1sg":"know","2sg":"know","3sg":"knows","1pl":"know","2pl":"know","3pl":"know"},"past_forms":{"1sg":"knew","2sg":"knew","3sg":"knew","1pl":"knew","2pl":"knew","3pl":"knew"}},{"lemma":"want","en":"chcieć","forms":{"1sg":"want","2sg":"want","3sg":"wants","1pl":"want","2pl":"want","3pl":"want"},"past_forms":{"1sg":"wanted","2sg":"wanted","3sg":"wanted","1pl":"wanted","2pl":"wanted","3pl":"wanted"}},{"lemma":"can / to be able","en":"móc","forms":{"1sg":"can","2sg":"can","3sg":"can","1pl":"can","2pl":"can","3pl":"can"},"past_forms":{"1sg":"could","2sg":"could","3sg":"could","1pl":"could","2pl":"could","3pl":"could"}},{"lemma":"must / have to","en":"musieć","forms":{"1sg":"must","2sg":"must","3sg":"must","1pl":"must","2pl":"must","3pl":"must"},"pa