bered"}},{"lemma":"dance","en":"tańczyć","forms":{"1sg":"dance","2sg":"dance","3sg":"dances","1pl":"dance","2pl":"dance","3pl":"dance"},"past_forms":{"1sg":"danced","2sg":"danced","3sg":"danced","1pl":"danced","2pl":"danced","3pl":"danced"}},{"lemma":"kiss","en":"całować","forms":{"1sg":"kiss","2sg":"kiss","3sg":"kisses","1pl":"kiss","2pl":"kiss","3pl":"kiss"},"past_forms":{"1sg":"kissed","2sg":"kissed","3sg":"kissed","1pl":"kissed","2pl":"kissed","3pl":"kissed"}},{"lemma":"wait","en":"czekać","forms":{"1sg":"wait","2sg":"wait","3sg":"waits","1pl":"wait","2pl":"wait","3pl":"wait"},"past_forms":{"1sg":"waited","2sg":"waited","3sg":"waited","1pl":"waited","2pl":"waited","3pl":"waited"}},{"lemma":"call (phone)","en":"dzwonić","forms":{"1sg":"call","2sg":"call","3sg":"calls","1pl":"call","2pl":"call","3pl":"call"},"past_forms":{"1sg":"called","2sg":"called","3sg":"called","1pl":"called","2pl":"called","3pl":"called"}},{"lemma":"feel","en":"czuć","forms":{"1sg":"feel","2sg":"feel","3sg":"feels","1pl":"feel","2pl":"feel","3pl":"feel"},"past_forms":{"1sg":"felt","2sg":"felt","3sg":"felt","1pl":"felt","2pl":"felt","3pl":"felt"}},{"lemma":"love","en":"kochać","forms":{"1sg":"love","2sg":"love","3sg":"loves","1pl":"love","2pl":"love","3pl":"love"},"past_forms":{"1sg":"loved","2sg":"loved","3sg":"loved","1pl":"loved","2pl":"loved","3pl":"loved"}},{"lemma":"help","en":"pomagać","forms":{"1sg":"help","2sg":"help","3sg":"helps","1pl":"help","2pl":"help","3pl":"help"},"past_forms":{"1sg":"helped","2sg":"helped","3sg":"helped","1pl":"helped","2pl":"helped","3pl":"helped"}},{"lemma":"ask / request","en":"prosić","forms":{"1sg":"ask","2sg":"ask","3sg":"asks","1pl":"ask","2pl":"ask","3pl":"ask"},"past_forms":{"1sg":"asked","2sg":"asked","3sg":"asked","1pl":"asked","2pl":"asked","3pl":"asked"}},{"lemma":"give","en":"dawać","forms":{"1sg":"give","2sg":"give","3sg":"gives","1pl":"give","2pl":"give","3pl":"give"},"past_forms":{"1sg":"gave","2sg":"gave","3sg":"gave","1pl":"gave","2pl":"gave","3pl":"gave"}},{"lemma":"take","en":"brać","forms":{"1sg":"take","2sg":"take","3sg":"takes","1pl":"take","2pl":"take","3pl":"take"},"past_forms":{"1sg":"took","2sg":"took","3sg":"took","1pl":"took","2pl":"took","3pl":"took"}},{"lemma":"think","en":"myśleć","forms":{"1sg":"think","2sg":"think","3sg":"thinks","1pl":"think","2pl":"think","3pl":"think"},"past_forms":{"1sg":"thought","2sg":"thought","3sg":"thought","1pl":"thought","2pl":"thought","3pl":"thought"}},{"lemma":"go (by vehicle)","en":"jechać","forms":{"1sg":"go","2sg":"go","3sg":"goes","1pl":"go","2pl":"go","3pl":"go"},"past_forms":{"1sg":"went","2sg":"went","3sg":"went","1pl":"went","2pl":"went","3pl":"went"}},{"lemma":"return / come back","en":"wracać","forms":{"1sg":"return","2sg":"return","3sg":"returns","1pl":"return","2pl":"return","3pl":"return"},"past_forms":{"1sg":"returned","2sg":"returned","3sg":"returned","1pl":"returned","2pl":"returned","3pl":"returned"}},{"lemma":"ask (a question)","en":"pytać","forms":{"1sg":"ask","2sg":"ask","3sg":"asks","1pl":"ask","2pl":"ask","3pl":"ask"},"past_forms":{"1sg":"asked","2sg":"asked","3sg":"asked","1pl":"asked","2pl":"asked","3pl":"asked"}}],"pronouns":[{"lemma":"I","en":"ja","case_forms":{"nom":"I","acc":"me","dat":"to me"}},{"lemma":"you","en":"ty","case_forms":{"nom":"you","acc":"you","dat":"to you"}},{"lemma":"he","en":"on","case_forms":{"nom":"he","acc":"him","dat":"to him"}},{"lemma":"she","en":"ona","case_forms":{"nom":"she","acc":"her","dat":"to her"}},{"lemma":"it","en":"ono","case_forms":{"nom":"it","acc":"it","dat":"to it"}},{"lemma":"we","en":"my","case_forms":{"nom":"we","acc":"us","dat":"to us"}},{"lemma":"y''all","en":"wy","case_forms":{"nom":"y''all","acc":"y''all","dat":"to y''all"}},{"lemma":"they","en":"oni / one","case_forms":{"nom":"they","acc":"them","dat":"to them"}}],"phrases":[{"en":"Widzę ją","pl":"I see her","focus":["verb.present.1sg","pronoun.acc.3sg.f"]},{"en":"Ona mnie widzi","pl":"She sees me","focus":["verb.present.3sg","pronoun.acc.1sg"]},{"en":"Lubisz go","pl":"You like him","focus":["verb.present.2sg","pronoun.acc.3sg.m"]},{"en":"On cię lubi","pl":"He likes you","focus":["verb.present.3sg","pronoun.acc.2sg"]},{"en":"My ich znamy","pl":"We know them","focus":["verb.present.1pl","pronoun.acc.3pl.m"]},{"en":"Oni nas widzą","pl":"They see us","focus":["verb.present.3pl","pronoun.acc.1pl"]},{"en":"Płacę ci","pl":"I pay you","focus":["verb.present.1sg","pronoun.dat.2sg"]},{"en":"Ona mu płaci","pl":"She pays him","focus":["verb.present.3sg","pronoun.dat.3sg.m"]},{"en":"Mam psa","pl":"I have a dog","focus":["verb.present.1sg"]},{"en":"Jemy chleb","pl":"We eat bread","focus":["verb.present.1pl"]},{"en":"On pije wodę","pl":"He drinks water","focus":["verb.present.3sg"]},{"en":"Jestem szczęśliwy","pl":"I am happy","focus":["verb.present.1sg.być"]},{"en":"Jesteś zmęczony","pl":"You are tired","focus":["verb.present.2sg.być"]},{"en":"Oni czytają książki","pl":"They read books","focus":["verb.present.3pl"]},{"en":"Robię to","pl":"I do it","focus":["verb.present.1sg"]},{"en":"Ona mówi po polsku","pl":"She speaks Polish","focus":["verb.present.3sg"]},{"en":"Idę do sklepu","pl":"I go to the store","focus":["verb.present.1sg.iść"]},{"en":"Znam go","pl":"I know him","focus":["verb.present.1sg","pronoun.acc.3sg.m"]},{"en":"Ona zna odpowiedź","pl":"She knows the answer","focus":["verb.present.3sg.znać"]},{"en":"Nie wiem","pl":"I don''t know","focus":["verb.present.1sg.wiedzieć"]},{"en":"Chcę kawę","pl":"I want coffee","focus":["verb.present.1sg.chcieć"]},{"en":"Możemy pomóc","pl":"We can help","focus":["verb.present.1pl.móc"]},{"en":"Musisz iść","pl":"You must go","focus":["verb.present.2sg.musieć"]},{"en":"Piszę list","pl":"I write a letter","focus":["verb.present.1sg.pisać"]},{"en":"Kupujemy chleb","pl":"We buy bread","focus":["verb.present.1pl.kupować"]},{"en":"Mieszkam w Warszawie","pl":"I live in Warsaw","focus":["verb.present.1sg.mieszkać"]},{"en":"On pracuje w domu","pl":"He works at home","focus"